import React from 'react';

const Navbar = ({ active, setActive, onGoHome }) => {
  const menuItems = ["Início", "Serviços", "Agendamentos", "Contato"];

  const handleNavClick = (item) => {
    // 1. Define o item como ativo para mudar a cor no menu
    setActive(item);

    // 2. Se for "Agendamentos", o seu App.js provavelmente já troca a tela.
    // Se não for, ele tenta rolar para a seção correspondente:
    if (item !== "Agendamentos") {
      // Transformamos o nome em ID (ex: "Serviços" vira "serviços")
      const sectionId = item.toLowerCase();
      const element = document.getElementById(sectionId);

      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
  };

  return (
    <nav className="pb-navbar">
      <div className="pb-brand" onClick={onGoHome} style={{ cursor: 'pointer' }}>
        <div className="pb-logo-wrap">
          <div className="pb-logo">
            <span className="pb-logo-text">PB</span>
          </div>
        </div>
        <div className="pb-brand-name">
          <span>Palheta</span>
          <span>Barbearia</span>
        </div>
      </div>

      <ul className="pb-nav-links">
        {/* Mantendo seu botão Home que volta para a Landing */}
        <li>
          <button 
            onClick={onGoHome} 
            className="pb-nav-link"
            style={{ color: 'var(--amarelo)', fontWeight: 'bold' }}
          >
            ← HOME
          </button>
        </li>

        {menuItems.map((item) => (
          <li key={item}>
            <button
              onClick={() => handleNavClick(item)}
              className={`pb-nav-link ${active === item ? "active" : ""}`}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
